nodes.expr:
Account.Order.Product.{
  "product": `Product Name`,
  "status": Price * Quantity >= $prioritySpend ? "priority" : "standard",
  "isAccessory": Category = "Accessories",
  "needsRestock": Quantity <= 2
}

(
  $assert($exists(Account.Contacts[Primary = true]), "Primary contact missing");
  {
    "primaryContact": Account.Contacts[Primary = true][0].Value,
    "activeRegion": Account.Region
  }
)

Account.Order.{
  "orderId": OrderID,
  "invoiceLines": Product.{
    "description": `Product Name` & " (" & SKU & ")",
    "qty": Quantity,
    "unitPrice": Price,
    "lineTotal": $round(Price * Quantity, 2),
    "withVat": $round((Price * Quantity) * (1 + $vatRate), 2)
  }
}

{
  "customer": customer.name,
  "eligibleOrders": orders[status = "paid" and total >= $minSpend].{
    "id": id,
    "total": total,
    "region": region
  },
  "eligibleCount": $count(orders[status = "paid" and total >= $minSpend])
}

