settings.customFunctions:
{
  slug: (value) => String(value).trim().toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, ''),
  initials: (value) => String(value).trim().split(/\s+/).map(part => part[0] || '').join('').toUpperCase(),
  joinWords: (parts) => Array.isArray(parts) ? parts.filter(Boolean).join(' ') : String(parts),
  formatMoney: {
    implementation: (value, currency) => new Intl.NumberFormat('en-US', { style: 'currency', currency: currency || 'USD' }).format(Number(value || 0)),
    description: 'Format a number using Intl currency formatting'
  }
}
